import React from 'react';
import styled from "styled-components";

import './Home.css';


const Appname = styled.div`
  font-size: 5vh;
  margin: 0;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: aliceblue;
  text-align: center;
`;


// Testing background
function Home() {
    return (
        <div class="background">
            <div class = "Appname">
                Climate Watch
            </div>
        </div>

    );
}

export default Home;
